import pymysql
import json
import os
from flask import escape

def search_api(request):
    request_args = request.args
    query_conditions = []
    values = []

    if request_args.get('name'):
        query_conditions.append("name LIKE %s")
        values.append(f"%{escape(request_args['name'])}%")
    
    if request_args.get('age'):
        query_conditions.append("age = %s")
        values.append(int(escape(request_args['age'])))

    if request_args.get('city'):
        query_conditions.append("city LIKE %s")
        values.append(f"%{escape(request_args['city'])}%")

    query = "SELECT * FROM your_table_name"
    if query_conditions:
        query += " WHERE " + " AND ".join(query_conditions)

    conn = pymysql.connect(
        user=os.environ['DB_USER'],
        password=os.environ['DB_PASS'],
        host=os.environ['DB_HOST'],
        database=os.environ['DB_NAME']
    )

    with conn.cursor() as cursor:
        cursor.execute(query, values)
        results = cursor.fetchall()

    conn.close()

    return json.dumps(results), 200, {'Content-Type': 'application/json'}